// Get agent output
const agentItem = $('Sales AI Agent').first().json;
const rawOutput =
  agentItem.output ||
  agentItem.text ||
  agentItem.message ||
  agentItem.content ||
  JSON.stringify(agentItem) ||
  "";

const question = $('Prepare Data Context').first().json.question || "";

// ── Lead detection by keyword matching on question + answer ──
const combined = (question + " " + rawOutput).toLowerCase();

const buyingKeywords = [
  "i want", "i need", "sign up", "get started", "how to get",
  "recommend", "which bundle", "which package", "which product",
  "suggest", "best for me", "best for my", "i am interested",
  "i'm interested", "purchase", "buy", "subscribe", "pkr",
  "for my office", "for my business", "for my home", "for my team",
  "how much", "cost for", "price for", "bundle for"
];

const excludeKeywords = [
  "total revenue", "collection rate", "unpaid", "how many customers",
  "top collector", "best collector", "which city", "which month",
  "revenue this", "how is", "what is our", "who is"
];

const hasIntent = buyingKeywords.some(k => combined.includes(k));
const isExcluded = excludeKeywords.some(k => combined.includes(k));
const isLead = hasIntent && !isExcluded;

// ── Extract product from agent response ──
const products = [
  "OMC + OTS", "OMC + DI + CMS", "OMC + CLOUD + CPaaS + D2D",
  "OMC + FFM", "AdsPro + Analytica", "FTTH", "CPaaS",
  "CLOUD", "AdsPro", "Analytica", "CMS", "D2D", "DI",
  "FFM", "OTS", "OMC", "Prepaid", "Postpaid"
];
let interestedProduct = "";
for (const p of products) {
  if (rawOutput.toUpperCase().includes(p.toUpperCase())) {
    interestedProduct = p;
    break;
  }
}

// ── Determine customer type ──
const bizWords = ["business", "office", "company", "team", "enterprise", "employees", "staff"];
const resWords = ["home", "residential", "house", "family", "personal"];
let customerType = "unknown";
if (bizWords.some(w => combined.includes(w))) customerType = "Business";
else if (resWords.some(w => combined.includes(w))) customerType = "Residential";

// ── Extract budget ──
const budgetMatch = combined.match(/(\d[\d,]*)\s*(pkr|rupee|rs)/i) ||
                    combined.match(/pkr\s*(\d[\d,]*)/i);
const budgetPkr = budgetMatch
  ? parseInt(budgetMatch[1].replace(/,/g, ""))
  : 0;

const leadData = isLead ? {
  is_lead: true,
  interested_product: interestedProduct,
  customer_type: customerType,
  budget_pkr: budgetPkr,
  reason: `Customer asked: "${question.slice(0, 80)}"`
} : null;

console.log("isLead:", isLead);
console.log("leadData:", JSON.stringify(leadData));

return [{
  json: {
    answer: rawOutput.trim(),
    isLead: isLead,
    leadData: leadData,
    question: question,
    timestamp: $('Prepare Data Context').first().json.timestamp,
    rawOutput: rawOutput
  }
}];

const query = $input.first().json.query;
const leadInfo = typeof query === "string" ? JSON.parse(query) : query;

return {
  json: {
    success: true,
    message: "Lead information recorded successfully",
    leadData: leadInfo
  }
};

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "is_lead": {
      "type": "boolean",
      "description": "True if the customer wants to buy, sign up, or get a product recommendation for themselves. False for general data questions."
    },
    "interested_product": {
      "type": "string",
      "description": "Product or bundle name e.g. OMC, FTTH, OMC + OTS. Empty string if not a lead."
    },
    "customer_type": {
      "type": "string",
      "description": "Business or Residential. Unknown if not clear."
    },
    "budget_pkr": {
      "type": "number",
      "description": "Monthly budget in PKR if mentioned. 0 if unknown."
    },
    "reason": {
      "type": "string",
      "description": "One sentence explaining why this person is a lead. Empty if not a lead."
    }
  },
  "required": ["is_lead", "interested_product", "customer_type", "budget_pkr", "reason"]
}
